import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.apache.commons.collections.buffer.steps"
)
public class CucumberTest {
}

package org.apache.commons.collections.buffer.steps;

import io.cucumber.java.en.*;
import org.apache.commons.collections.buffer.UnboundedFifoBuffer;
import java.io.*;

import static org.junit.Assert.*;

public class UnboundedFifoBufferSteps {
    private UnboundedFifoBuffer buffer;
    private Object deserializedBuffer;

    @Given("an empty UnboundedFifoBuffer")
    public void an_empty_unbounded_fifo_buffer() {
        buffer = new UnboundedFifoBuffer();
        assertEquals(0, buffer.size());
    }

    @When("the buffer is serialized and then deserialized")
    public void the_buffer_is_serialized_and_then_deserialized() throws IOException, ClassNotFoundException {
        // Serialize to byte array
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        ObjectOutputStream oos = new ObjectOutputStream(baos);
        oos.writeObject(buffer);
        oos.close();

        // Deserialize from byte array
        ByteArrayInputStream bais = new ByteArrayInputStream(baos.toByteArray());
        ObjectInputStream ois = new ObjectInputStream(bais);
        deserializedBuffer = ois.readObject();
        ois.close();

        // Use the deserialized buffer
        buffer = (UnboundedFifoBuffer) deserializedBuffer;
    }

    @And("I add the element {string} to the buffer")
    public void i_add_the_element_to_the_buffer(String element) {
        buffer.add(element);
    }

    @Then("the buffer size should be {int}")
    public void the_buffer_size_should_be(int expectedSize) {
        assertEquals(expectedSize, buffer.size());
    }
}

